<?php

$path = __DIR__.'/../resources/views/comercio/dashboard.blade.php';
$content = file_get_contents($path);

if ($content === false) {
    fwrite(STDERR, "ERROR: No se pudo leer dashboard.blade.php\n");
    exit(1);
}

$catalogMarker = 'data-commerce-tab-panel="catalogos"';
$brandingMarker = 'data-commerce-tab-panel="branding"';

$catalogMarkerPosition = strpos($content, $catalogMarker);
$brandingMarkerPosition = strpos($content, $brandingMarker);

if ($catalogMarkerPosition === false || $brandingMarkerPosition === false || $brandingMarkerPosition <= $catalogMarkerPosition) {
    fwrite(STDERR, "ERROR: No se pudieron ubicar los paneles Catalogos y Branding.\n");
    exit(1);
}

$catalogStart = strrpos(substr($content, 0, $catalogMarkerPosition), '<div');

if ($catalogStart === false) {
    fwrite(STDERR, "ERROR: No se encontro el inicio del panel Catalogos.\n");
    exit(1);
}

$brandingStart = strrpos(substr($content, 0, $brandingMarkerPosition), '<div');

if ($brandingStart === false || $brandingStart <= $catalogStart) {
    fwrite(STDERR, "ERROR: No se encontro el inicio del panel Branding.\n");
    exit(1);
}

$panel = base64_decode('', true);

if ($panel === false) {
    fwrite(STDERR, "ERROR: No se pudo decodificar el nuevo panel Catalogos.\n");
    exit(1);
}

$content = substr($content, 0, $catalogStart)
    .$panel."\n\n"
    .substr($content, $brandingStart);

$content = preg_replace(
    '~comercio-catalogos\.css\'\) \}\}\?v=[^"\']+~',
    "comercio-catalogos.css') }}?v=20260712-02",
    $content,
    1
);

$content = preg_replace(
    '~comercio-catalogos\.js\'\) \}\}\?v=[^"\']+~',
    "comercio-catalogos.js') }}?v=20260712-02",
    $content,
    1
);

if (file_put_contents($path, $content) === false) {
    fwrite(STDERR, "ERROR: No se pudo guardar dashboard.blade.php\n");
    exit(1);
}

echo "OK: Panel Catalogos V2 reemplazado.\n";